Fix bot executeAndReply - poll for task:
## Analysis

The current bot flow is broken because:
1. `callACC('/api/execute')` returns a taskId but never polls for completion
2. The bot shows a spinner indefinitely because no result is ever sent back
3. There's no timeout mechanism or error recovery

## Fixed Code

### 1. New helper function: `executeAndReply`

javascript
// cloud/telegram/bot.js - Add this function

const axios = require('axios');
const ACC_API_BASE = 'http://localhost:4000';

/**
 * Execute an AI task and poll for completion, sending updates to the user
 * @param {string} chatId - Telegram chat ID
 * @param {string} agentType - Type of agent (e.g., 'writer', 'chef')
 * @param {object} payload - The prompt/input payload
 * @param {function} sendFn - Function to send messages (bot.sendMessage)
 * @param {string} userId - User ID for tracking
 * @returns {Promise<string>} - The result text
 */
async function executeAndReply(chatId, agentType, payload, sendFn, userId) {
  try {
    // Step 1: Send initial working message
    await sendFn(chatId, '⏳ Working on it...');

    // Step 2: Call execute endpoint
    const executeResponse = await callACC('/api/execute', {
      agentType,
      payload,
      userId
    });

    if (!executeResponse.success || !executeResponse.taskId) {
      throw new Error('Failed to start task: ' + (executeResponse.error || 'Unknown error'));
    }

    const taskId = executeResponse.taskId;
    const startTime = Date.now();
    const TIMEOUT = 30000; // 30 seconds
    const POLL_INTERVAL = 2000; // 2 seconds

    // Step 3: Poll for completion
    while (Date.now() - startTime < TIMEOUT) {
      await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));

      try {
        const taskResponse = await axios.get(`${ACC_API_BASE}/api/task/${taskId}`);
        const task = taskResponse.data;

        if (task.status === 'completed') {
          const result = task.result?.output || task.output || 'Task completed but no output returned';
          await sendFn(chatId, result);
          return result;
        }

        if (task.status === 'failed' || task.status === 'error') {
          const errorMsg = task.error || task.result?.error || 'Unknown error';
          await sendFn(chatId, `❌ Error: ${errorMsg}`);
          throw new Error(errorMsg);
        }

        // Still processing - continue polling
      } catch (pollError) {
        if (pollError.response?.status === 404) {
          // Task not found yet - might be initializing
          continue;
        }
        throw pollError;
      }
    }

    // Step 4: Timeout reached
    await sendFn(chatId, 'Still processing... send /latesttask to check');
    throw new Error('Task timed out after 30 seconds');

  } catch (error) {
    // Send error message if not already sent
    const errorMessage = error.message || 'Unknown error occurred';
    await sendFn(chatId, `❌ Error: ${errorMessage}`).catch(() => {});
    throw error;
  }
}


