## Analysis & Fix: ACC Bot Feature Handlers

### Root Causes Identified

1. **Notes not saving**: `addNote()` in `cloud/telegram/features/notes.js` uses a relative path `data/storage/{userId}/.notes.enc` but doesn't verify directory existence or catch write errors. The path may not exist in REDACTED.

2. **Chef AI stuck searching**: `callACC('/api/execute')` queues a task but never polls for completion. The bot sends "searching..." but never delivers the result.

3. **Translate not working**: Handler in `bot.js` likely calls `callACC` without proper result handling, or returns empty response.

4. **Resume tailoring**: Same polling issue as Chef.

### Complete Fixed Function

javascript
// Add this to cloud/telegram/bot.js (or a shared utils file)

async function executeAndReply(chatId, prompt, sendFn) {
  const MAX_POLL_TIME = 30000; // 30 seconds
  const POLL_INTERVAL = 2000;  // 2 seconds

  try {
    // 1. Queue task via /api/execute
    sendFn(chatId, { text: '⏳ Processing your request...' });

    const executeResponse = await callACC('/api/execute', {
      method: 'POST',
      body: JSON.stringify({ prompt })
    });

    if (!executeResponse || !executeResponse.taskId) {
      throw new Error('Failed to queue task - no taskId returned');
    }

    const taskId = executeResponse.taskId;

    // 2. Poll for result every 2s, max 30s
    let result = null;
    const startTime = Date.now();

    while (Date.now() - startTime < MAX_POLL_TIME) {
      await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));

      try {
        const statusResponse = await callACC(`/api/task/${taskId}`);

        if (statusResponse.status === 'completed') {
          result = statusResponse.result;
          break;
        } else if (statusResponse.status === 'failed') {
          throw new Error(statusResponse.error || 'Task failed');
        }
        // If 'running' or 'queued', continue polling
      } catch (pollError) {
        // Log but continue polling - network issues shouldn't break the loop
        console.error(`Poll error for task ${taskId}:`, pollError.message);
      }
    }

    // 3. Send result back to chatId
    if (result) {
      sendFn(chatId, { text: result });
    } else {
      // 4. If timeout
      sendFn(chatId, { 
        text: '⏰ Still working... Check /latesttask for updates.' 
      });
    }

  } catch (error) {
    // Handle errors gracefully - never leave user with no response
    console.error('executeAndReply error:', error);
    sendFn(chatId, { 
      text: `❌ Error: ${error.message || 'Something went wrong. Please try again.'}` 
    });
  }
}


